#!/bin/bash
# Generated by GitHub Copilot
# Créateur et modificateur d'agents canoniques.
# Usage : ./oc.sh agent <commande> [args]

source "$(cd "$(dirname "$0")" && pwd)/common.sh"

# EXTERNAL_SKILLS_DIR est défini dans common.sh

# ── HELPERS ──────────────────────────────────────────────────────────────────

##
# Construit la liste de tous les skills disponibles (locaux + externes).
# Imprime un skill par ligne sous la forme "chemin/relatif" (sans .md).
##
_list_all_skills() {
  # Skills locaux
  find "$HUB_DIR/skills" -name "*.md" \
      -not -path "*/external/*" \
      -type f 2>/dev/null | sort \
    | while IFS= read -r f; do
        echo "${f#$HUB_DIR/skills/}" | sed 's/\.md$//'
      done

  # Skills externes
  if [ -d "$EXTERNAL_SKILLS_DIR" ]; then
    find "$EXTERNAL_SKILLS_DIR" -name "*.md" \
        -not -name ".sources.json" \
        -type f 2>/dev/null | sort \
      | while IFS= read -r f; do
          name=$(basename "$f" .md)
          echo "external/$name"
        done
  fi
}

##
# Rendu d'une page du sélecteur de skills (compatible bash 3.2).
# Variables utilisées depuis _pick_skills : all_skills, checked, cursor, page_size, total, total_pages
##
##
# Rendu du sélecteur de skills (compatible bash 3.2).
# Variables utilisées depuis _pick_skills (dynamic scoping bash) :
#   all_skills, checked, cursor, page_size, total
##
_render_skills_page() {
  local win_start=$(( cursor - page_size / 2 ))
  [ "$win_start" -lt 0 ] && win_start=0
  local win_end=$(( win_start + page_size ))
  [ "$win_end" -gt "$total" ] && win_end=$total
  # Réajuster win_start si on est proche de la fin
  win_start=$(( win_end - page_size ))
  [ "$win_start" -lt 0 ] && win_start=0

  printf "\033[2J\033[H"  # clear screen

  # ── En-tête ──────────────────────────────────────────────────────────────
  echo -e "${BOLD}Sélection des skills${RESET}  ($((cursor+1))/$total)"
  echo -e "  \033[0;34m↑↓\033[0m naviguer   \033[0;34mespace\033[0m cocher/décocher   \033[0;34mentrée\033[0m valider   \033[0;34mESC\033[0m annuler   \033[0;34m0\033[0m tout vider"
  echo ""

  # ── Liste (fenêtre glissante) ─────────────────────────────────────────────
  local i=$win_start
  while [ "$i" -lt "$win_end" ]; do
    local skill="${all_skills[$i]}"
    local num=$((i + 1))

    local check_icon="   "
    local check_color=""
    local check_reset=""
    if [ "${checked[$i]}" = "1" ]; then
      check_icon="[x]"
      check_color="$GREEN"
      check_reset="$RESET"
    fi

    if [ "$i" -eq "$cursor" ]; then
      printf "  \033[1m> ${check_color}%-3s${check_reset}\033[1m %3d. %-50s\033[0m\n" \
        "$check_icon" "$num" "$skill"
    else
      printf "    ${check_color}%-3s${check_reset} %3d. %-50s\n" \
        "$check_icon" "$num" "$skill"
    fi
    i=$((i + 1))
  done

  # ── Séparateur ────────────────────────────────────────────────────────────
  echo ""
  printf "  \033[0;34m%s\033[0m\n" "────────────────────────────────────────────────────────────"

  # ── Panneau description du skill sous le curseur ──────────────────────────
  local cur_skill="${all_skills[$cursor]}"
  local cur_desc=""
  local skill_file="$HUB_DIR/skills/${cur_skill}.md"
  [ -f "$skill_file" ] && cur_desc=$(grep '^description:' "$skill_file" | head -1 | sed 's/^description:[[:space:]]*//')

  echo ""
  printf "  \033[1m%s\033[0m\n" "$cur_skill"
  if [ -n "$cur_desc" ]; then
    printf "  %s\n" "$cur_desc"
  else
    printf "  \033[2m(pas de description)\033[0m\n"
  fi

  # ── Pied ──────────────────────────────────────────────────────────────────
  echo ""
  local count=0
  local v
  for v in "${checked[@]}"; do [ "$v" = "1" ] && count=$((count+1)); done
  echo -e "  ${BOLD}$count skill(s) sélectionné(s)${RESET}"
  echo ""
}

##
# Menu interactif de sélection de skills avec navigation flèches + espace.
# Compatible bash 3.2 (macOS). Résultat dans $PICKED_SKILLS (CSV).
# Appeler directement (pas dans une sous-shell).
# @param {string} $1 — sélection courante (CSV de noms de skills)
##
_pick_skills() {
  local current_csv="${1:-}"
  local page_size=10

  # Charger tous les skills
  local all_skills=()
  while IFS= read -r s; do
    all_skills+=("$s")
  done < <(_list_all_skills)

  if [ ${#all_skills[@]} -eq 0 ]; then
    log_warn "Aucun skill disponible."
    PICKED_SKILLS="$current_csv"
    return
  fi

  local total=${#all_skills[@]}

  # Nettoyer current_csv : retirer guillemets et espaces superflus
  local clean_csv
  clean_csv=$(echo "$current_csv" | tr -d '"' | tr ',' '\n' | sed 's/^ *//;s/ *$//' | grep -v '^$' | tr '\n' ',' | sed 's/,$//')

  # Tableau booléen de sélection (bash 3.2 : pas d'array associatif)
  local checked=()
  local i=0
  while [ "$i" -lt "$total" ]; do
    local skill="${all_skills[$i]}"
    if echo ",$clean_csv," | grep -qF ",$skill,"; then
      checked+=("1")
    else
      checked+=("0")
    fi
    i=$((i + 1))
  done

  local cursor=0

  # Sauvegarde état terminal et passage en mode raw
  local old_stty
  old_stty=$(stty -g </dev/tty 2>/dev/null)
  # Restauration garantie même en cas d'interruption (Ctrl-C, set -e, etc.)
  trap '[ -n "$old_stty" ] && stty "$old_stty" </dev/tty 2>/dev/null' EXIT INT TERM
  stty -echo -icanon min 1 time 0 </dev/tty 2>/dev/null

  local _picker_cancelled=0

  while true; do
    _render_skills_page

    # Lecture d'une touche
    local key byte1 byte2 byte3
    IFS= read -rsn1 byte1 </dev/tty
    key="$byte1"

    # Séquence d'échappement (flèches) : ESC [ X
    if [ "$byte1" = $'\x1b' ]; then
      IFS= read -rsn1 -t 1 byte2 </dev/tty || byte2=""
      if [ "$byte2" = "[" ] || [ "$byte2" = "O" ]; then
        IFS= read -rsn1 -t 1 byte3 </dev/tty || byte3=""
        key="${byte1}${byte2}${byte3}"
      elif [ -z "$byte2" ]; then
        # ESC seul → annuler le sélecteur
        _picker_cancelled=1
        break
      else
        key="${byte1}${byte2}"
      fi
    fi

    case "$key" in
      $'\x1b[A'|$'\x1bOA')  # flèche haut
        [ "$cursor" -gt 0 ] && cursor=$((cursor - 1))
        ;;
      $'\x1b[B'|$'\x1bOB')  # flèche bas
        [ "$cursor" -lt $((total - 1)) ] && cursor=$((cursor + 1))
        ;;
      " ")  # espace — toggle
        if [ "${checked[$cursor]}" = "1" ]; then
          checked[$cursor]="0"
        else
          checked[$cursor]="1"
        fi
        ;;
      ""| $'\n'| $'\r')  # entrée — valider
        break
        ;;
      "0")
        i=0
        while [ "$i" -lt "$total" ]; do checked[$i]="0"; i=$((i+1)); done
        ;;
    esac
  done

  # Restaurer le terminal et désarmer le trap
  trap - EXIT INT TERM
  [ -n "$old_stty" ] && stty "$old_stty" </dev/tty 2>/dev/null

  # Annulation par ESC : conserver la sélection courante
  if [ "$_picker_cancelled" = "1" ]; then
    printf "\033[2J\033[H"
    log_warn "Sélection annulée (ESC) — skills inchangés."
    PICKED_SKILLS="$current_csv"
    return
  fi

  printf "\033[2J\033[H"  # clear après sortie

  # Reconstruire le CSV final
  local chosen=()
  i=0
  while [ "$i" -lt "$total" ]; do
    [ "${checked[$i]}" = "1" ] && chosen+=("${all_skills[$i]}")
    i=$((i + 1))
  done

  PICKED_SKILLS=$(printf '%s\n' "${chosen[@]}" | tr '\n' ',' | sed 's/,$//')
}

##
# Sélection de cibles (targets) pour l'agent.
# @param {string} $1 — Valeur courante (CSV)
# Écrit la sélection finale sur stdout.
##
_pick_targets() {
  local current="${1:-opencode, claude-code, vscode}"
  local available=("opencode" "claude-code" "vscode")

  echo ""
  echo -e "${BOLD}Cibles disponibles :${RESET}"
  echo "  (Entrez les numéros séparés par des espaces)"
  echo ""

  local i=1
  for t in "${available[@]}"; do
    if echo "$current" | grep -q "$t"; then
      echo -e "  ${GREEN}[x]${RESET} $i. $t"
    else
      echo "      $i. $t"
    fi
    i=$((i + 1))
  done
  echo ""

  read -rp "Numéros des cibles (laisser vide = toutes) : " selection

  if [ -z "$selection" ]; then
    echo "opencode, claude-code, vscode"
    return
  fi

  local chosen=()
  for num in $selection; do
    if ! echo "$num" | grep -qE '^[0-9]+$'; then continue; fi
    if [ "$num" -lt 1 ] || [ "$num" -gt "${#available[@]}" ]; then continue; fi
    chosen+=("${available[$((num - 1))]}")
  done

  printf '%s\n' "${chosen[@]}" | tr '\n' ', ' | sed 's/, $//'
}

##
# Réécrit le frontmatter d'un agent existant avec de nouvelles valeurs.
# @param {string} $1 — Chemin du fichier agent
# @param {string} $2 — Nouvelle valeur de skills (CSV → format YAML liste inline)
# @param {string} $3 — Nouvelle valeur de targets (CSV → format YAML liste inline)
# @param {string} $4 — Nouveau label
# @param {string} $5 — Nouvelle description
##
_update_frontmatter() {
  local file="$1" skills_csv="$2" targets_csv="$3" label="$4" description="$5"

  # Convertir CSV en format YAML inline ["a", "b", "c"]
  local skills_yaml
  skills_yaml=$(printf '%s\n' "$skills_csv" | tr ',' '\n' | sed 's/^ *//' | sed 's/ *$//' | grep -v '^$' | sed 's/.*/"&"/' | tr '\n' ',' | sed 's/,$//' | sed 's/^/[/' | sed 's/$/]/')

  local targets_yaml
  targets_yaml=$(printf '%s\n' "$targets_csv" | tr ',' '\n' | sed 's/^ *//' | sed 's/ *$//' | grep -v '^$' | sed 's/.*/"&"/' | tr '\n' ',' | sed 's/,$//' | sed 's/^/[/' | sed 's/$/]/')

  # Extraire le corps (sans frontmatter)
  local body
  body=$(awk 'BEGIN{f=0;d=0} /^---$/{if(!f){f=1;next}else if(!d){d=1;next}} d{print}' "$file")

  # Reconstruire le fichier avec le nouveau frontmatter
  local agent_id
  agent_id=$(basename "$file" .md)

  # Écriture avec printf pour éviter l'expansion des variables utilisateur
  # (un heredoc non-quoté expand $label/$description — risque si elles contiennent $ ou `)
  {
    printf '%s\n' "---"
    printf 'id: %s\n'          "$agent_id"
    printf 'label: %s\n'       "$label"
    printf 'description: %s\n' "$description"
    printf 'targets: %s\n'     "$targets_yaml"
    printf 'skills: %s\n'      "$skills_yaml"
    printf '%s\n' "---"
  } > "$file"

  # Ré-append le corps en évitant un saut de ligne double
  printf '%s\n' "$body" >> "$file"
}

# ── LIST ─────────────────────────────────────────────────────────────────────

##
# Liste les agents canoniques disponibles dans agents/.
##
cmd_list() {
  log_title "Agents canoniques"
  echo ""

  local found=0
  for f in "$CANONICAL_AGENTS_DIR"/*.md; do
    [ -f "$f" ] || continue
    local id label description targets skills_count
    id=$(grep '^id:' "$f" | head -1 | sed 's/^id:[[:space:]]*//')
    label=$(grep '^label:' "$f" | head -1 | sed 's/^label:[[:space:]]*//')
    description=$(grep '^description:' "$f" | head -1 | sed 's/^description:[[:space:]]*//')
    skills_count=$(grep '^skills:' "$f" | head -1 | tr ',' '\n' | grep -v '^$' | wc -l | tr -d ' ')
    targets=$(grep '^targets:' "$f" | head -1 | sed 's/^targets:[[:space:]]*//')
    echo -e "  ${BOLD}${id}${RESET}  (${label})"
    echo "    → $description"
    echo "    cibles : $targets"
    echo "    skills : $skills_count skill(s) configuré(s)"
    echo ""
    found=1
  done

  [ "$found" -eq 0 ] && echo "  (aucun agent dans agents/)"
}

# ── INFO ─────────────────────────────────────────────────────────────────────

##
# Affiche le détail d'un agent (frontmatter + liste complète des skills).
# @param {string} $1 — Identifiant ou nom de fichier de l'agent
##
cmd_info() {
  local name="${1:-}"
  if [ -z "$name" ]; then
    log_error "Usage : oc agent info <agent-id>"
    exit 1
  fi

  local file="$CANONICAL_AGENTS_DIR/${name}.md"
  [ -f "$file" ] || { log_error "Agent '$name' introuvable dans agents/."; exit 1; }

  log_title "Agent : $name"
  echo ""
  sed -n '/^---$/,/^---$/p' "$file" | grep -v '^---$'
  echo ""
  echo -e "${BOLD}Skills assignés :${RESET}"
  grep '^skills:' "$file" | head -1 \
    | sed 's/^skills:[[:space:]]*//' \
    | tr -d '[]' | tr ',' '\n' \
    | sed 's/^ *//' | sed 's/ *$//' | grep -v '^$' \
    | while IFS= read -r skill; do
        cleaned=$(echo "$skill" | tr -d '"')
        local skill_file="$HUB_DIR/skills/${cleaned}.md"
        if [ -f "$skill_file" ]; then
          echo -e "  ${GREEN}✔${RESET}  $cleaned"
        else
          echo -e "  ${YELLOW}⚠${RESET}  $cleaned  (fichier absent)"
        fi
      done
}

# ── CREATE ───────────────────────────────────────────────────────────────────

##
# Crée un nouvel agent canonique de façon interactive.
##
cmd_create() {
  log_title "Créer un nouvel agent"
  echo ""

  # Identifiant
  read -rp "Identifiant (ex: reviewer) : " agent_id
  agent_id=$(echo "$agent_id" | tr '[:upper:]' '[:lower:]' | sed 's/[^a-z0-9_-]/-/g')
  if [ -z "$agent_id" ]; then
    log_error "Identifiant requis."
    exit 1
  fi

  local file="$CANONICAL_AGENTS_DIR/${agent_id}.md"
  if [ -f "$file" ]; then
    log_error "L'agent '$agent_id' existe déjà. Utilisez 'oc agent edit $agent_id'."
    exit 1
  fi

  # Label
  read -rp "Label (nom court, ex: CodeReviewer) [${agent_id}] : " label
  label="${label:-$agent_id}"

  # Description
  read -rp "Description : " description
  description="${description:-Assistant $label}"

  # Targets
  local targets_csv
  targets_csv=$(_pick_targets "opencode, claude-code, vscode")
  log_info "Cibles : $targets_csv"

  # Skills
  PICKED_SKILLS=""
  _pick_skills ""
  local skills_csv="$PICKED_SKILLS"
  if [ -z "$skills_csv" ]; then
    log_warn "Aucun skill sélectionné."
  else
    log_info "Skills : $skills_csv"
  fi

  # Corps par défaut
  local body
  body=$(cat << BODY

# 🤖 ${label}

${description}

## Ce que tu fais
- TODO : décrire les responsabilités de cet agent

## Workflow
1. TODO : décrire le workflow
BODY
)

  # Construire le frontmatter
  local skills_yaml targets_yaml
  skills_yaml=$(printf '%s\n' "$skills_csv" | tr ',' '\n' | sed 's/^ *//' | sed 's/ *$//' | grep -v '^$' | sed 's/.*/"&"/' | tr '\n' ',' | sed 's/,$//' | sed 's/^/[/' | sed 's/$/]/')
  targets_yaml=$(printf '%s\n' "$targets_csv" | tr ',' '\n' | sed 's/^ *//' | sed 's/ *$//' | grep -v '^$' | sed 's/.*/"&"/' | tr '\n' ',' | sed 's/,$//' | sed 's/^/[/' | sed 's/$/]/')

  # Créer le fichier avec printf pour éviter l'expansion des variables utilisateur
  {
    printf '%s\n' "---"
    printf 'id: %s\n'          "$agent_id"
    printf 'label: %s\n'       "$label"
    printf 'description: %s\n' "$description"
    printf 'targets: %s\n'     "$targets_yaml"
    printf 'skills: %s\n'      "$skills_yaml"
    printf '%s\n' "---"
  } > "$file"
  printf '%s\n' "$body" >> "$file"

  echo ""
  log_success "Agent '$agent_id' créé → agents/${agent_id}.md"
  log_info    "Personnalisez le corps dans agents/${agent_id}.md"
  log_info    "Puis déployez : ./oc.sh deploy all"
}

# ── EDIT ─────────────────────────────────────────────────────────────────────

##
# Modifie les métadonnées et les skills d'un agent existant de façon interactive.
# @param {string} $1 — Identifiant de l'agent à modifier
##
cmd_edit() {
  local name="${1:-}"
  if [ -z "$name" ]; then
    log_error "Usage : oc agent edit <agent-id>"
    log_info  "Utilisez 'oc agent list' pour voir les agents disponibles."
    exit 1
  fi

  local file="$CANONICAL_AGENTS_DIR/${name}.md"
  [ -f "$file" ] || { log_error "Agent '$name' introuvable dans agents/."; exit 1; }

  log_title "Modifier l'agent : $name"

  # Lire les valeurs courantes
  local cur_label cur_desc cur_targets cur_skills
  cur_label=$(grep '^label:' "$file" | head -1 | sed 's/^label:[[:space:]]*//')
  cur_desc=$(grep '^description:' "$file" | head -1 | sed 's/^description:[[:space:]]*//')
  cur_targets=$(grep '^targets:' "$file" | head -1 | sed 's/^targets:[[:space:]]*//' | tr -d '[]"')
  cur_skills=$(grep '^skills:' "$file" | head -1 | sed 's/^skills:[[:space:]]*//' | tr -d '[]"')

  echo ""
  echo -e "  label       : ${BOLD}${cur_label}${RESET}"
  echo   "  description : $cur_desc"
  echo   "  targets     : $cur_targets"
  echo   "  skills      : $cur_skills"
  echo ""

  # Label
  read -rp "Nouveau label [${cur_label}] : " new_label
  new_label="${new_label:-$cur_label}"

  # Description
  read -rp "Nouvelle description [${cur_desc}] : " new_desc
  new_desc="${new_desc:-$cur_desc}"

  # Targets
  echo ""
  read -rp "Modifier les cibles ? (y/N) : " edit_targets
  local new_targets="$cur_targets"
  if [[ "$edit_targets" =~ ^[Yy]$ ]]; then
    new_targets=$(_pick_targets "$cur_targets")
    log_info "Cibles : $new_targets"
  fi

  # Skills (toujours proposé)
  PICKED_SKILLS=""
  _pick_skills "$cur_skills"
  local new_skills="$PICKED_SKILLS"
  log_info "Skills : ${new_skills:-aucun}"

  # Valider avant écriture
  echo ""
  echo -e "${BOLD}Récapitulatif des modifications :${RESET}"
  echo "  label       : $new_label"
  echo "  description : $new_desc"
  echo "  targets     : $new_targets"
  echo "  skills      : $new_skills"
  echo ""
  read -rp "Appliquer ? (Y/n) : " confirm
  confirm="${confirm:-Y}"
  [[ "$confirm" =~ ^[Yy]$ ]] || { log_info "Annulé."; exit 0; }

  _update_frontmatter "$file" "$new_skills" "$new_targets" "$new_label" "$new_desc"

  echo ""
  log_success "Agent '$name' mis à jour → agents/${name}.md"
  log_info    "Relancez le déploiement pour appliquer : ./oc.sh deploy all"
}

# ── KEYTEST ──────────────────────────────────────────────────────────────────

##
# Diagnostic TTY : affiche les octets reçus pour chaque touche pressée.
# Permet de vérifier ce que le terminal envoie réellement pour les flèches,
# espace, entrée, ESC, etc.
# Quitter avec q ou Ctrl-C.
##
cmd_keytest() {
  echo -e "${BOLD}Diagnostic clavier (oc agent keytest)${RESET}"
  echo "Appuyez sur des touches pour voir les octets reçus."
  echo "Quittez avec  q  ou  Ctrl-C."
  echo ""

  local old_stty
  old_stty=$(stty -g </dev/tty 2>/dev/null)
  # Restauration garantie même en cas d'interruption
  trap 'stty "$old_stty" </dev/tty 2>/dev/null; echo ""; exit 0' INT TERM EXIT

  stty -echo -icanon min 1 time 0 </dev/tty 2>/dev/null

  while true; do
    local byte1 byte2 byte3
    IFS= read -rsn1 byte1 </dev/tty

    # Lire bytes supplémentaires si séquence ESC
    local extra=""
    if [ "$byte1" = $'\x1b' ]; then
      IFS= read -rsn1 -t 1 byte2 </dev/tty || byte2=""
      extra="$byte2"
      if [ "$byte2" = "[" ] || [ "$byte2" = "O" ]; then
        IFS= read -rsn1 -t 1 byte3 </dev/tty || byte3=""
        extra="${byte2}${byte3}"
      fi
    fi

    local full_seq="${byte1}${extra}"

    # Affichage hex + description lisible
    local hex
    hex=$(printf '%s' "$full_seq" | xxd -p 2>/dev/null || printf '%s' "$full_seq" | od -An -tx1 | tr -d ' \n')

    # Description humaine
    local desc=""
    case "$full_seq" in
      $'\x1b[A') desc="flèche HAUT" ;;
      $'\x1b[B') desc="flèche BAS" ;;
      $'\x1b[C') desc="flèche DROITE" ;;
      $'\x1b[D') desc="flèche GAUCHE" ;;
      $'\x1b')   desc="ESC seul" ;;
      " ")        desc="ESPACE" ;;
      $'\n')      desc="ENTRÉE (LF)" ;;
      $'\r')      desc="ENTRÉE (CR)" ;;
      "q"|"Q")
        desc="q — sortie"
        printf "  hex=%-20s  %s\n" "$hex" "$desc"
        break
        ;;
    esac

    printf "  hex=%-20s  repr=%-10s  %s\n" \
      "$hex" \
      "$(printf '%s' "$full_seq" | cat -v 2>/dev/null || echo '?')" \
      "$desc"
  done

  # Le trap gère la restauration
  trap - INT TERM EXIT
  stty "$old_stty" </dev/tty 2>/dev/null
  echo ""
  echo -e "${GREEN}Terminal restauré.${RESET}"
}

# ── DISPATCH ─────────────────────────────────────────────────────────────────

SUBCOMMAND="${1:-}"
shift 2>/dev/null || true

case "$SUBCOMMAND" in
  list)    cmd_list ;;
  info)    cmd_info "$@" ;;
  create)  cmd_create ;;
  edit)    cmd_edit "$@" ;;
  keytest) cmd_keytest ;;
  *)
    echo -e "${BOLD}oc agent — Gestion des agents canoniques${RESET}"
    echo ""
    echo "  list              Lister les agents disponibles"
    echo "  info <agent-id>   Afficher le détail d'un agent"
    echo "  create            Créer un nouvel agent (interactif)"
    echo "  edit <agent-id>   Modifier les skills et métadonnées d'un agent"
    echo "  keytest           Diagnostic clavier — affiche les octets reçus"
    echo ""
    echo -e "${BOLD}Exemples :${RESET}"
    echo "  ./oc.sh agent list"
